+}
+
+// =============================================================================
+// 7. Plan total consistency
+// =============================================================================
+
+proptest! {
+    /// The sum of per-target segments_to_remove must equal total_segments_to_remove.
+    #[test]
+    fn proptest_plan_total_consistency(
